var bins = _.range(0.01, 1, 0.05);
var thresholdBins = _.range(0, 1, 0.05);

var discretizeBeta = function(g, d){
  var shape_alpha = g * d;
  var shape_beta = (1-g) * d;
  var betaPDF = function(x){
    return Math.pow(x, shape_alpha-1) * Math.pow((1-x), shape_beta-1);
  };
  return map(betaPDF, bins);
};

var structuredPriorModel = function(params){
  return Infer({method: "enumerate"}, function(){
    var potential = params["potential"];
    var g = params["prevalenceWhenPresent"];
    var d = params["concentrationWhenPresent"];
    var propertyIsPresent = flip(potential);
    var prevalence = propertyIsPresent ?
        categorical(discretizeBeta(g,d), bins) : 0;
    return prevalence;
  });
};

var alpha_1 = 5;
var alpha_2 = 1;

var utterances = ["Bears eat honey", "A bear eats honey", "silence"];

var thresholdPrior = function() { return uniformDraw(thresholdBins); };
var utterancePrior = function() { return uniformDraw(utterances); };

var prevalencePrior = structuredPriorModel({
  potential: 0.3,
  prevalenceWhenPresent: 0.5,
  concentrationWhenPresent: 2
});

var meaning = function(utterance, prevalence, positiveExamples, threshold, sense, context) {
  return utterance === "silence" ? true :
    sense === "generic" ? prevalence > threshold :
    context == 0 ? true :
    utterance === "A bear eats honey" ? positiveExamples >= 1 :
    utterance === "The bears eat honey" ? positiveExamples >= 2 :
    utterance === "The bear eats honey" ? positiveExamples === 1 :
    utterance === "Bears eat honey" ? positiveExamples >= 2 :
    true;
};

var literalListener = cache(function(utterance, threshold, sense, context) {
  return Infer({method: "enumerate"}, function(){
    var prevalence = sample(prevalencePrior);
    var positiveExamples = context > 0 ? prevalence > 0 ? binomial({p: prevalence, n: context}) : 0 : 0;
    var m = meaning(utterance, prevalence, positiveExamples, threshold, sense, context);
    condition(m);
    return {prevalence: prevalence, positiveExamples: positiveExamples};
  });
});

var speaker1 = cache(function(threshold, sense, context, prevalence, positiveExamples) {
  return Infer({method: "enumerate"}, function(){
    var utterance = utterancePrior();
    var L0 = literalListener(utterance, threshold, sense, context);
    var qudVal = {prevalence: prevalence, positiveExamples: positiveExamples};
    factor(alpha_1 * L0.score(qudVal));
    return utterance;
  });
});

var pragmaticListener = function(utterance, observedContext) {
  return Infer({method: "enumerate"}, function(){
    var prevalence = sample(prevalencePrior);
    var context = observedContext ? 5 : 0;
    var positiveExamples = context > 0 ? prevalence > 0 ? binomial({p: prevalence, n: context}) : 0 : 0;
    var sense = uniformDraw(["generic", "specific"]);
    var threshold = sense === "generic" ? uniformDraw(thresholdBins) : -9;
    var S1 = speaker1(threshold, sense, context, prevalence, positiveExamples);
    observe(S1, utterance);
    return sense;
  });
};

var posterior = pragmaticListener("A bear eats honey", true);
var posterior2 = pragmaticListener("A bear eats honey", false);
var ANSWER = {
  specificInterpretationWithContext: Math.exp(posterior.score("specific")),
  specificInterpretationWithoutContext: Math.exp(posterior2.score("specific"))
};

var states =
   [
  {pregnant : 1, embarrassed : 0},
  {pregnant : 0, embarrassed : 1 }
];

var statePrior = function() {
  return categorical({ps: [40,60], vs: states});
};

var utterances = ["pregnant", "embarrassed"];

var utterancePrior = function(){
  return uniformDraw(utterances);
};

var cost = function(utterance) { return 0; };

var meaning = function(state, utterance){
  return utterance == "pregnant" ? state.pregnant == 1 : state.embarrassed == 1;
};

var alpha = 1;

var chunkMaker = function(nChunksLeft, word, chunksSoFar) {
  var chunksSoFar = chunksSoFar == undefined ? [] : chunksSoFar;
  if (nChunksLeft == 0) {
    return chunksSoFar;
  } else {
    var newChunk = word[nChunksLeft-1][0]+word[nChunksLeft-1][1];
    var newChunksSoFar = chunksSoFar.concat([newChunk]);
    return chunkMaker(nChunksLeft - 1, word, newChunksSoFar);
  }
};

var chunker = function(utterance) {
  var chunk_org = _.chunk(utterance, 2);
  var chunk_1 = _.chunk(_.toArray(utterance).slice(1), 2);
  var chunks = _.union(chunk_org, chunk_1);
  return chunkMaker(chunks.length, chunks);
};

var similarity = function(word1, word2) {
  return ((_.intersection(chunker(word1),chunker(word2))).length*2) /
    (chunker(word1).length + chunker(word2).length);
};

var translate = function(utterance, competence){
  if (utterance == "embarrassed" && competence == "high")
    return "avergonzada";
  if (utterance == "embarrassed" && competence == "low")
    return similarity("embarazada", "embarrassed") > similarity("avergonzada", "embarrassed")
      ? "embarazada" : "avergonzada";
  if (utterance == "pregnant" && competence == "high")
    return "embarazada";
  if (utterance == "pregnant" && competence == "low")
    return similarity("avergonzada", "pregnant") > similarity("embarazada", "pregnant")
      ? "avergonzada" : "embarazada";
};

var literalListener = cache(function(utterance) {
  return Infer({model: function(){
    var state = statePrior();
    condition(meaning(state, utterance));
    return state;
  }});
});

var speaker = function(state, competence) {
  return Infer({model: function() {
    var utterance = utterancePrior();
    factor(alpha*(literalListener(utterance).score(state) - cost(utterance)));
    return translate(utterance, competence);
  }});
};

var pragmaticListener = cache(function(translation) {
  return Infer({model: function(){
    var state = statePrior();
    var competence = uniformDraw(["high", "low"]);
    observe(speaker(state, competence), translation);
    return {state: state, competence: competence};
  }});
});

