var getTransitions = function (str) {
  var result = [];
  var splitStr = str.split(" ");
  var indices = _.range(splitStr.length);
  map(function (i) {
    var transition = splitStr.slice(0, i + 1).join(" ");
    result.push(transition);
  }, indices);
  return result;
};

