  var allContinuations = filter(function (x) { return x.startsWith(context); }, utterances);
  var trueContinuations = reduce(
    function (x, acc) { return stringMeanings(x, state) + acc; },
    0,
    allContinuations
  );
  return safeDivide(trueContinuations, allContinuations.length);
};

